from typing import List, Optional
from collections import deque

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def build_tree(nodes: List[Optional[int]]) -> Optional[TreeNode]:
    if not nodes or nodes[0] is None:
        return None
    root = TreeNode(nodes[0])
    queue = deque([root])
    i = 1
    while queue and i < len(nodes):
        node = queue.popleft()
        if i < len(nodes) and nodes[i] is not None:
            node.left = TreeNode(nodes[i])
            queue.append(node.left)
        i += 1
        if i < len(nodes) and nodes[i] is not None:
            node.right = TreeNode(nodes[i])
            queue.append(node.right)
        i += 1
    return root

def is_same_tree(p: List[Optional[int]], q: List[Optional[int]]) -> bool:
    p = build_tree(p)
    q = build_tree(q)

    def same(a, b):
        if not a and not b:
            return True
        if not a or not b:
            return False
        return a.val == b.val and same(a.left, b.left) and same(a.right, b.right)

    return same(p, q)

class TreeNode {
  constructor(val = 0, left = null, right = null) { this.val = val; this.left = left; this.right = right; }
}
function buildTree(nodes) {
  if (!nodes || nodes.length === 0 || nodes[0] === null) return null;
  const root = new TreeNode(nodes[0]); const queue = [root]; let i = 1;
  while (queue.length > 0 && i < nodes.length) {
    const node = queue.shift();
    if (i < nodes.length && nodes[i] !== null) { node.left = new TreeNode(nodes[i]); queue.push(node.left); } i++;
    if (i < nodes.length && nodes[i] !== null) { node.right = new TreeNode(nodes[i]); queue.push(node.right); } i++;
  }
  return root;
}
function isSameTree(p, q) {
    p = buildTree(p);
    q = buildTree(q);
    function same(a, b) {
        if (!a && !b) return true;
        if (!a || !b) return false;
        return a.val === b.val && same(a.left, b.left) && same(a.right, b.right);
    }
    return same(p, q);
}
